#include <stdexcept>

template <typename T>
class AvgPartition {
private:
    std::vector<T> lst;
    int limit;

public:
    AvgPartition(std::vector<T> lst, int limit) : lst(std::move(lst)), limit(limit) {}

    std::pair<int, int> setNum() const {
        if (limit == 0) {
            throw std::runtime_error("ZeroDivisionError"); // To mimic Python
        }
        int size = lst.size() / limit;
        int remainder = lst.size() % limit;
        return {size, remainder};
    }

    std::vector<T> get(int index) const {
        auto [size, remainder] = setNum();
        int start = index * size + std::min(index, remainder);
        int end = start + size;
        if (index + 1 <= remainder) {
            end += 1;
        }

        // Mimic Python's slice lst[start:end]
        size_t s = std::max(0, std::min(start, (int)lst.size()));
        size_t e = std::max(0, std::min(end, (int)lst.size()));

