        int check_time = parse_time(check_time_str);

        for (const auto& course : courses) {
            int start_time = parse_time(course.start_time);
            int end_time = parse_time(course.end_time);
            if (start_time <= check_time && check_time <= end_time) {
                return false;
            }
        }
