        std::string result;
        for (size_t i = 0; i < binary_string.size(); i += 8) {
            std::string byte_str = binary_string.substr(i, 8);
            unsigned long decimal = binary_to_ulong(byte_str);
            result += static_cast<char>(decimal);
        }
        validate_utf8(result);
        return result;
