        }
        return result;
    }

    void validate_utf8(const std::string& str) {
        for (size_t i = 0; i < str.size(); ) {
            unsigned char c = str[i];
            int num_bytes = 0;

            if ((c & 0x80) == 0x00) {
                num_bytes = 1;
            } else if ((c & 0xE0) == 0xC0) {
                num_bytes = 2;
            } else if ((c & 0xF0) == 0xE0) {
                num_bytes = 3;
            } else if ((c & 0xF8) == 0xF0) {
                num_bytes = 4;
            } else {
