            }

            if (i + num_bytes > str.size()) {
                throw std::runtime_error("UnicodeDecodeError");
            }

            for (int j = 1; j < num_bytes; ++j) {
                if ((static_cast<unsigned char>(str[i + j]) & 0xC0) != 0x80) {
