    std::pair<std::vector<std::string>, std::vector<std::vector<std::string>>> read_csv(const std::string& file_name) {
        std::vector<std::vector<std::string>> all_rows;

        std::ifstream file(file_name);
        std::string content((std::istreambuf_iterator<char>(file)),
                            std::istreambuf_iterator<char>());

        size_t pos = 0;
        while (pos < content.size()) {
            std::vector<std::string> row = parse_row(content, pos);
            all_rows.push_back(row);
        }

        std::vector<std::string> title;
        std::vector<std::vector<std::string>> data;

        if (!all_rows.empty()) {
            title = all_rows[0];
            for (size_t i = 1; i < all_rows.size(); i++) {
                data.push_back(all_rows[i]);
            }
        }

        return std::make_pair(title, data);
    }

    int write_csv(const std::vector<std::vector<std::string>>& data, const std::string& file_name) {
        try {
            std::ofstream file(file_name);
            if (!file) return 0;
            for (size_t i = 0; i < data.size(); i++) {
                file << format_row(data[i]) << "\n";
            }
            return file ? 1 : 0;
        } catch (...) {
            return 0;
        }
    }

    int process_csv_data(int N, const std::string& save_file_name) {
        std::pair<std::vector<std::string>, std::vector<std::vector<std::string>>> result = read_csv(save_file_name);
        std::vector<std::string> title = result.first;
        std::vector<std::vector<std::string>> data = result.second;

        std::vector<std::string> column_data;
        for (size_t i = 0; i < data.size(); i++) {
            std::string val = data[i][N];
            std::transform(val.begin(), val.end(), val.begin(), [](unsigned char c) { return std::toupper(c); });
            column_data.push_back(val);
        }

        std::vector<std::vector<std::string>> new_data;
        new_data.push_back(title);
        new_data.push_back(column_data);

        std::string base_name = save_file_name;
        size_t dot_pos = base_name.find('.');
        if (dot_pos != std::string::npos) {
            base_name = base_name.substr(0, dot_pos);
        }

        return write_csv(new_data, base_name + "_process.csv");
    }

private:
    std::vector<std::string> parse_row(const std::string& content, size_t& pos) {
        std::vector<std::string> fields;
        std::string field;
        bool in_quotes = false;

        while (pos < content.size()) {
            char c = content[pos];

            if (in_quotes) {
                if (c == '"') {
                    if (pos + 1 < content.size() && content[pos + 1] == '"') {
                        field += '"';
                        pos += 2;
                    } else {
                        in_quotes = false;
                        pos++;
                    }
                } else {
                    field += c;
                    pos++;
                }
            } else {
                if (c == '"') {
                    in_quotes = true;
                    pos++;
                } else if (c == ',') {
                    fields.push_back(field);
                    field.clear();
                    pos++;
                } else if (c == '\r') {
                    pos++;
                    if (pos < content.size() && content[pos] == '\n') {
                        pos++;
                    }
                    break;
                } else if (c == '\n') {
                    pos++;
                    break;
                } else {
                    field += c;
                    pos++;
                }
            }
        }

        fields.push_back(field);
        return fields;
    }

    std::string format_row(const std::vector<std::string>& row) {
        std::string result;
        for (size_t i = 0; i < row.size(); i++) {
            if (i > 0) result += ",";
            result += quote_field(row[i]);
        }
        return result;
    }

    std::string quote_field(const std::string& field) {
        bool needs_quoting = false;
        for (size_t i = 0; i < field.size(); i++) {
            char c = field[i];
            if (c == ',' || c == '"' || c == '\n' || c == '\r') {
                needs_quoting = true;
                break;
            }
        }

        if (!needs_quoting) {
            return field;
        }

        std::string quoted = "\"";
        for (size_t i = 0; i < field.size(); i++) {
            char c = field[i];
            if (c == '"') {
                quoted += "\"\"";
            } else {
                quoted += c;
            }
        }
        quoted += "\"";
        return quoted;
    }
};
