class Interpolation {
public:
    Interpolation() {}

    static std::vector<double> interpolate_1d(const std::vector<double>& x,
                                               const std::vector<double>& y,
                                               const std::vector<double>& x_interp) {
        std::vector<double> y_interp;
        for (double xi : x_interp) {
            for (size_t i = 0; i + 1 < x.size(); ++i) {
                if (x[i] <= xi && xi <= x[i + 1]) {
                    double yi = y[i] + (y[i + 1] - y[i]) * (xi - x[i]) / (x[i + 1] - x[i]);
                    y_interp.push_back(yi);
                    break;
                }
            }
        }
        return y_interp;
    }

    static std::vector<double> interpolate_2d(const std::vector<double>& x,
                                               const std::vector<double>& y,
                                               const std::vector<std::vector<double>>& z,
                                               const std::vector<double>& x_interp,
                                               const std::vector<double>& y_interp) {
        std::vector<double> z_interp;
        size_t n = std::min(x_interp.size(), y_interp.size());
        for (size_t k = 0; k < n; ++k) {
            double xi = x_interp[k];
            double yi = y_interp[k];
            for (size_t i = 0; i + 1 < x.size(); ++i) {
                if (x[i] <= xi && xi <= x[i + 1]) {
                    for (size_t j = 0; j + 1 < y.size(); ++j) {
                        if (y[j] <= yi && yi <= y[j + 1]) {
                            double z00 = z[i][j];
                            double z01 = z[i][j + 1];
                            double z10 = z[i + 1][j];
                            double z11 = z[i + 1][j + 1];
                            double zi = (z00 * (x[i + 1] - xi) * (y[j + 1] - yi) +
                                         z10 * (xi - x[i]) * (y[j + 1] - yi) +
                                         z01 * (x[i + 1] - xi) * (yi - y[j]) +
                                         z11 * (xi - x[i]) * (yi - y[j])) /
                                        ((x[i + 1] - x[i]) * (y[j + 1] - y[j]));
                            z_interp.push_back(zi);
                            break;
                        }
                    }
                    break;
                }
            }
        }
        return z_interp;
    }
};
```

### Key translation notes:

1. **`zip` behavior**: Python's `zip(x_interp, y_interp)` iterates up to the shorter list. In C++, this is replicated with `std::min(x_interp.size(), y_interp.size())` and indexed iteration.

2. **`range(len(x) - 1)`**: Translated as `size_t i = 0; i + 1 < x.size(); ++i`. Using `i + 1 < x.size()` avoids unsigned underflow that `i < x.size() - 1` would cause when `x` is empty (since `x.size() - 1` would wrap around for `size_t(0)`).

3. **Chained comparison `x[i] <= xi <= x[i+1]`**: Python's chained comparison is split into `x[i] <= xi && xi <= x[i + 1]` in C++.

4. **`break` semantics**: The nested `break` statements in the inner loops replicate Python's behavior — the inner `break` exits the `j`-loop, then the outer `break` exits the `i`-loop, moving to the next interpolation point.

5. **No-match behavior**: If an interpolation point doesn't fall within any interval, it is silently skipped (no value appended), matching the Python behavior.

