```cpp
#include <OpenXLSX.hpp>
#include <string>
#include <vector>
#include <variant>
#include <optional>
#include <algorithm>
#include <cctype>
#include <sstream>
#include <utility>

class ExcelProcessor {
public:
    using CellValue = std::variant<std::string, int64_t, double>;
    using Row = std::vector<CellValue>;
    using DataTable = std::vector<Row>;

    ExcelProcessor() = default;

    std::optional<DataTable> read_excel(const std::string& file_name) {
        DataTable data;
        try {
            OpenXLSX::XLDocument doc;
            doc.open(file_name);
            auto wb = doc.workbook();
            auto ws = wb.worksheet(1);

            auto dim = ws.dimension();
            unsigned int rowCount = dim.rowCount();
            unsigned int colCount = dim.colCount();

            for (unsigned int r = 1; r <= rowCount; ++r) {
                Row rowData;
                for (unsigned int c = 1; c <= colCount; ++c) {
                    auto cell = ws.cell(r, c);
                    auto val = cell.value();

                    if (val.type() == OpenXLSX::XLValueType::String) {
                        rowData.emplace_back(val.get<std::string>());
                    } else if (val.type() == OpenXLSX::XLValueType::Integer) {
                        rowData.emplace_back(val.get<int64_t>());
                    } else if (val.type() == OpenXLSX::XLValueType::Float) {
                        rowData.emplace_back(val.get<double>());
                    } else if (val.type() == OpenXLSX::XLValueType::Boolean) {
                        rowData.emplace_back(val.get<bool>() ? std::string("TRUE") : std::string("FALSE"));
                    } else {
                        rowData.emplace_back(std::string(""));
                    }
                }
                data.push_back(std::move(rowData));
            }

            doc.close();
            return data;
        } catch (...) {
            return std::nullopt;
        }
    }

    int write_excel(const DataTable& data, const std::string& file_name) {
        try {
            OpenXLSX::XLDocument doc;
            doc.create(file_name);
            auto wb = doc.workbook();
            auto ws = wb.worksheet(1);

            for (size_t i = 0; i < data.size(); ++i) {
                const auto& row = data[i];
                for (size_t j = 0; j < row.size(); ++j) {
                    auto cell = ws.cell(static_cast<unsigned int>(i + 1),
                                        static_cast<unsigned int>(j + 1));
                    std::visit([&cell](const auto& v) {
                        using T = std::decay_t<decltype(v)>;
                        if constexpr (std::is_same_v<T, std::string>) {
                            cell.value() = v;
                        } else if constexpr (std::is_same_v<T, int64_t>) {
                            cell.value() = v;
                        } else if constexpr (std::is_same_v<T, double>) {
                            cell.value() = v;
                        }
                    }, row[j]);
                }
            }

            doc.save();
            doc.close();
            return 1;
        } catch (...) {
            return 0;
        }
    }

    using ProcessResult = std::variant<int, std::pair<int, std::string>>;

    ProcessResult process_excel_data(int N, const std::string& save_file_name) {
        auto data_opt = read_excel(save_file_name);
        if (!data_opt.has_value() || static_cast<size_t>(N) >= data_opt.value()[0].size()) {
            return 0;
        }

        DataTable new_data;
        for (const auto& row : data_opt.value()) {
            Row new_row = row;
            const auto& cell_val = row[static_cast<size_t>(N)];
            std::string str_val = cell_to_string(cell_val);

            if (!is_all_digits(str_val)) {
                std::string upper_val = to_upper(str_val);
                new_row.emplace_back(std::move(upper_val));
            } else {
                new_row.push_back(cell_val);
            }
            new_data.push_back(std::move(new_row));
        }

        std::string new_file_name = get_process_filename(save_file_name);
        int success = write_excel(new_data, new_file_name);
        return std::make_pair(success, new_file_name);
    }

private:
    static std::string cell_to_string(const CellValue& cell) {
        return std::visit([](const auto& v) -> std::string {
            using T = std::decay_t<decltype(v)>;
            if constexpr (std::is_same_v<T, std::string>) {
                return v;
            } else if constexpr (std::is_same_v<T, int64_t>) {
                return std::to_string(v);
            } else if constexpr (std::is_same_v<T, double>) {
                std::ostringstream oss;
                oss << v;
                return oss.str();
            }
            return "";
        }, cell);
    }

    static bool is_all_digits(const std::string& s) {
        if (s.empty()) return false;
        return std::all_of(s.begin(), s.end(), [](unsigned char c) {
            return std::isdigit(c);
        });
    }

    static std::string to_upper(const std::string& s) {
        std::string result = s;
        std::transform(result.begin(), result.end(), result.begin(),
                       [](unsigned char c) { return std::toupper(c); });
        return result;
    }

    static std::string get_process_filename(const std::string& filename) {
        auto dot_pos = filename.find('.');
        if (dot_pos != std::string::npos) {
            return filename.substr(0, dot_pos) + "_process.xlsx";
        }
        return filename + "_process.xlsx";
    }
};
```

