        hp += 10;
        if (hp > 100) {
            hp = 100;
        }
        return hp;
    }

    void gain_exp(int amount) {
        while (amount != 0) {
            if (exp + amount >= level * 100) {
                amount -= (level * 100 - exp);
                level_up();
            } else {
                exp += amount;
                amount = 0;
            }
        }
