static int parse_base(const std::string& str, int base) {
    if (str.empty()) {
        throw std::invalid_argument("invalid literal");
    }
    size_t i = 0;
    bool is_negative = false;
    if (str[0] == '-') {
        is_negative = true;
        i = 1;
    } else if (str[0] == '+') {
        i = 1;
    }
    if (i == str.size()) {
        throw std::invalid_argument("invalid literal");
    }
    long long result = 0;
    for (; i < str.size(); ++i) {
        char c = str[i];
        int digit;
        if (c >= '0' && c <= '9') {
            digit = c - '0';
        } else if (c >= 'a' && c <= 'z') {
            digit = c - 'a' + 10;
        } else if (c >= 'A' && c <= 'Z') {
            digit = c - 'A' + 10;
        } else {
            throw std::invalid_argument("invalid literal");
        }
        if (digit >= base) {
            throw std::invalid_argument("invalid literal");
        }
        result = result * base + digit;
    }
    if (is_negative) {
        result = -result;
    }
    return static_cast<int>(result);
}
