#include <stdexcept>
#include <string>

class Parser {
public:
    Parser(const std::string& expr) : expr_(expr), pos_(0) {}

    double parse() {
        double result = parseExpression();
        skipSpaces();
        if (pos_ < expr_.size()) {
            throw std::runtime_error("Unexpected character");
        }
        return result;
    }

private:
    std::string expr_;
    size_t pos_;

    void skipSpaces() {
        while (pos_ < expr_.size() && std::isspace(expr_[pos_])) {
            pos_++;
        }
    }

    double parseExpression() {
        double result = parseTerm();
        while (true) {
            skipSpaces();
            if (pos_ < expr_.size() && (expr_[pos_] == '+' || expr_[pos_] == '-')) {
                char op = expr_[pos_++];
                double term = parseTerm();
                if (op == '+') {
                    result += term;
                } else {
                    result -= term;
                }
            } else {
                break;
            }
        }
        return result;
    }

    double parseTerm() {
        double result = parseFactor();
        while (true) {
            skipSpaces();
            if (pos_ < expr_.size() && (expr_[pos_] == '*' || expr_[pos_] == '/')) {
                char op = expr_[pos_++];
                double factor = parseFactor();
                if (op == '*') {
                    result *= factor;
                } else {
                    if (factor == 0) {
                        throw std::runtime_error("Division by zero");
                    }
                    result /= factor;
                }
            } else {
                break;
            }
        }
        return result;
    }

    double parseFactor() {
        skipSpaces();
        if (pos_ < expr_.size() && expr_[pos_] == '(') {
            pos_++;
            double result = parseExpression();
            skipSpaces();
            if (pos_ < expr_.size() && expr_[pos_] == ')') {
                pos_++;
            } else {
                throw std::runtime_error("Missing closing parenthesis");
            }
            return result;
        } else if (pos_ < expr_.size() && (expr_[pos_] == '-' || expr_[pos_] == '+')) {
            // unary plus/minus
            char op = expr_[pos_++];
            double factor = parseFactor();
            return op == '-' ? -factor : factor;
        } else {
            return parseNumber();
        }
    }

    double parseNumber() {
        skipSpaces();
        size_t start_pos = pos_;
        while (pos_ < expr_.size() && std::isdigit(expr_[pos_])) {
            pos_++;
        }
        if (pos_ == start_pos) {
            throw std::runtime_error("Expected number");
        }
        return std::stod(expr_.substr(start_pos, pos_ - start_pos));
    }
};

