#include <vector>
#include <cstdio>
#include <algorithm>
#include <filesystem>

extern "C" {
#include <zip.h>
#include <unzip.h>
}

class ZipFileProcessor {
private:
    std::string file_name_;

public:
    ZipFileProcessor(const std::string& file_name) : file_name_(file_name) {}

    unzFile read_zip_file() {
        try {
