            unzFile zf = unzOpen(file_name_.c_str());
            if (zf == nullptr) return false;

            unz_global_info gi;
            if (unzGetGlobalInfo(zf, &gi) != UNZ_OK) {
                unzClose(zf);
                return false;
            }

            for (uLong i = 0; i < gi.number_entry; i++) {
                unz_file_info fi;
                char filename[256];
                if (unzGetCurrentFileInfo(zf, &fi, filename, sizeof(filename),
                                          nullptr, 0, nullptr, 0) != UNZ_OK) {
                    unzClose(zf);
                    return false;
                }

                std::string entry_name(filename);
                std::filesystem::path full_path = std::filesystem::path(output_path) / entry_name;

                if (!entry_name.empty() && entry_name.back() == '/') {
                    std::filesystem::create_directories(full_path);
                } else {
                    std::filesystem::create_directories(full_path.parent_path());

                    if (unzOpenCurrentFile(zf) != UNZ_OK) {
                        unzClose(zf);
                        return false;
                    }

                    FILE* outfile = fopen(full_path.string().c_str(), "wb");
                    if (outfile == nullptr) {
                        unzCloseCurrentFile(zf);
                        unzClose(zf);
                        return false;
                    }

                    char buffer[4096];
                    int bytes_read;
                    while ((bytes_read = unzReadCurrentFile(zf, buffer, sizeof(buffer))) > 0) {
                        fwrite(buffer, 1, bytes_read, outfile);
                    }

                    fclose(outfile);
                    unzCloseCurrentFile(zf);
                }

                if (i + 1 < gi.number_entry) {
                    if (unzGoToNextFile(zf) != UNZ_OK) {
                        unzClose(zf);
                        return false;
                    }
                }
            }

            unzClose(zf);
            return true;
        } catch (...) {
            return false;
        }
    }

    bool extract_file(const std::string& file_name, const std::string& output_path) {
        try {
            unzFile zf = unzOpen(file_name_.c_str());
            if (zf == nullptr) return false;

            if (unzLocateFile(zf, file_name.c_str(), 0) != UNZ_OK) {
                unzClose(zf);
                return false;
            }

            unz_file_info fi;
            char filename[256];
            if (unzGetCurrentFileInfo(zf, &fi, filename, sizeof(filename),
                                      nullptr, 0, nullptr, 0) != UNZ_OK) {
                unzClose(zf);
                return false;
            }

            std::filesystem::path full_path = std::filesystem::path(output_path) / file_name;
            std::filesystem::create_directories(full_path.parent_path());

            if (unzOpenCurrentFile(zf) != UNZ_OK) {
                unzClose(zf);
                return false;
            }

            FILE* outfile = fopen(full_path.string().c_str(), "wb");
            if (outfile == nullptr) {
                unzCloseCurrentFile(zf);
                unzClose(zf);
                return false;
            }

            char buffer[4096];
            int bytes_read;
            while ((bytes_read = unzReadCurrentFile(zf, buffer, sizeof(buffer))) > 0) {
                fwrite(buffer, 1, bytes_read, outfile);
            }

            fclose(outfile);
            unzCloseCurrentFile(zf);
            unzClose(zf);
            return true;
        } catch (...) {
            return false;
        }
    }

    bool create_zip_file(const std::vector<std::string>& files,
                         const std::string& output_file_name) {
        try {
            zipFile zf = zipOpen(output_file_name.c_str(), APPEND_STATUS_CREATE);
            if (zf == nullptr) return false;

            for (const auto& file : files) {
                zip_fileinfo zi = {};

                FILE* infile = fopen(file.c_str(), "rb");
                if (infile == nullptr) {
                    zipClose(zf, nullptr);
                    return false;
                }

                // Use file path as entry name, normalizing path separators
                std::string entry_name = file;
                std::replace(entry_name.begin(), entry_name.end(), '\\', '/');

                if (zipOpenNewFileInZip(zf, entry_name.c_str(), &zi,
                                        nullptr, 0, nullptr, 0, nullptr,
                                        Z_DEFLATED, Z_DEFAULT_COMPRESSION) != ZIP_OK) {
                    fclose(infile);
                    zipClose(zf, nullptr);
                    return false;
                }

                char buffer[4096];
                size_t bytes_read;
                while ((bytes_read = fread(buffer, 1, sizeof(buffer), infile)) > 0) {
                    if (zipWriteInFileInZip(zf, buffer, static_cast<unsigned int>(bytes_read)) != ZIP_OK) {
                        fclose(infile);
                        zipCloseFileInZip(zf);
                        zipClose(zf, nullptr);
                        return false;
                    }
                }

                fclose(infile);
                zipCloseFileInZip(zf);
            }

            zipClose(zf, nullptr);
            return true;
        } catch (...) {
            return false;
        }
    }
};

#endif // ZIP_FILE_PROCESSOR_H
